import { describe, expect, it } from 'vitest';
import { forkRaceFoldDeblur } from '../src/forkraceFoldDeblur';
import { computeHornObservabilityRuntime } from '../src/horn-observability-runtime';
import {
  MESH_CARRIER_ASSESSMENT_CERTIFICATE_VERSION,
  MESH_HTTP_HEADER_CARRIER_DEBLUR_FOLD,
  attachDeblurEnsembleToMeshCarrierAssessmentJson,
  computeMeshCarrierNoiseSignalFromAssessments,
  encodeMeshCarrierAssessmentV1Json,
  mergeDeblurFoldIntoMeshCarrierJson,
  meshCarrierRequestHeadersWithDeblurEnsemble,
  toMeshCarrierAssessmentWire,
} from '../src/mesh-carrier-assessment';
import {
  classifyMeshAttentionClosure,
  classifySpectralNoise,
  requestEntropy,
  TOWER_CEILINGS,
} from '../src/spectral-noise-monitor';

describe('mesh carrier assessment wire', () => {
  it('computes the hexon brown horn observability schema numbers', () => {
    const horn = computeHornObservabilityRuntime({
      boundaryAtResolution: 90,
      stableRows: 2,
      source: 'attention_closure',
    });

    expect(horn.unresolvedResidue).toBe(88);
    expect(horn.absorbedInfo).toBe(2);
    expect(horn.carrierReadiness).toBe(-86);
    expect(horn.carrierReadinessDeficit).toBe(86);
    expect(horn.baselineObservabilityScore).toBe(-86);
    expect(horn.witnessedObservabilityScore).toBe(-84);
    expect(horn.witnessLift).toBe(2);
    expect(horn.carrierReady).toBe(false);
    expect(horn.partialObservation).toBe(true);
    expect(horn.recoverableWithWitness).toBe(true);
    expect(horn.theoremLineage).toContain(
      'Gnosis.HornObservabilityMetrics.matched_horn_escape_observability_schema',
    );
  });

  it('round-trips spectral + attention closure certificateVersion', () => {
    const trace = {
      requestId: 'req-1',
      nodeIdx: 2,
      chunkIdx: 0,
      startPos: 0,
      sequenceLength: 4,
      latencyMs: 80,
      expectedLatencyMs: 25,
      requestEntropy: requestEntropy(4, 2),
      boundaryLimit: 8,
      timestamp: 1_700_000_000_000,
    };
    let assessment = classifySpectralNoise(trace, [], TOWER_CEILINGS.hexon);
    assessment = {
      ...assessment,
      attentionClosure: classifyMeshAttentionClosure({
        heads: 8,
        coupling: 0,
        observerResolution: 12,
      }),
    };
    const wire = toMeshCarrierAssessmentWire({
      stationLayerStart: 2,
      stationLayerEndExclusive: 3,
      spectral: assessment,
    });
    expect(wire.certificateVersion).toBe(MESH_CARRIER_ASSESSMENT_CERTIFICATE_VERSION);
    expect(wire.stationLayerStart).toBe(2);
    expect(wire.attentionClosure?.telemetryLabel.length).toBeGreaterThan(0);
    expect(wire.attentionClosure?.theoremLineage.length).toBeGreaterThan(0);
    expect(wire.hornObservability?.source).toBe('attention_closure');
    expect(wire.hornObservability?.boundaryAtResolution).toBe(24);
    expect(wire.hornObservability?.stableRows).toBe(12);
    expect(wire.hornObservability?.unresolvedResidue).toBe(12);
    expect(wire.hornObservability?.carrierReadiness).toBe(0);
    expect(wire.hornObservability?.witnessedObservabilityScore).toBe(2);
    expect(wire.hornObservability?.residueMatchesObservation).toBe(true);

    const json = encodeMeshCarrierAssessmentV1Json({
      stationLayerStart: 2,
      stationLayerEndExclusive: 3,
      spectral: assessment,
    });
    expect(json).toContain(MESH_CARRIER_ASSESSMENT_CERTIFICATE_VERSION);
    const parsed = JSON.parse(json) as {
      spectral: { state: string };
      hornObservability: { schemaVersion: string; theoremLineage: string[] };
      epistemic: { outcome: string; limitationClasses: string[]; summary: string };
    };
    expect(parsed.spectral.state).toBe(assessment.state);
    expect(parsed.hornObservability.schemaVersion).toBe(
      'horn_observability_runtime/v1',
    );
    expect(parsed.hornObservability.theoremLineage).toContain(
      'Gnosis.HornLayeredResidue.horn_escape_maps_to_unresolved_residue',
    );
    expect(['claim_admitted', 'claim_withheld']).toContain(parsed.epistemic.outcome);
    expect(parsed.epistemic.limitationClasses).toContain(
      'global_optimality_unavailable',
    );
    expect(parsed.epistemic.limitationClasses).toContain('closure_lift_pressure');
    expect(parsed.epistemic.summary.length).toBeGreaterThan(0);
  });

  it('epistemic claim_withheld when entropy exceeds boundary', () => {
    const trace = {
      requestId: 'req-boundary',
      nodeIdx: 0,
      chunkIdx: 0,
      startPos: 0,
      sequenceLength: 1,
      latencyMs: 5,
      expectedLatencyMs: 25,
      requestEntropy: 32,
      boundaryLimit: 8,
      timestamp: 1,
    };
    const assessment = classifySpectralNoise(trace, [], TOWER_CEILINGS.hexon);
    expect(assessment.state).toBe('boundary_collapse');
    const json = encodeMeshCarrierAssessmentV1Json({
      stationLayerStart: 0,
      stationLayerEndExclusive: 1,
      spectral: assessment,
    });
    const parsed = JSON.parse(json) as {
      hornObservability: {
        source: string;
        unresolvedResidue: number;
        carrierReadinessDeficit: number;
        witnessedObservabilityScore: number;
      };
      epistemic: { outcome: string; limitationClasses: string[] };
    };
    expect(parsed.hornObservability.source).toBe('spectral_trace');
    expect(parsed.hornObservability.unresolvedResidue).toBe(24);
    expect(parsed.hornObservability.carrierReadinessDeficit).toBe(16);
    expect(parsed.hornObservability.witnessedObservabilityScore).toBe(-14);
    expect(parsed.epistemic.outcome).toBe('claim_withheld');
    expect(parsed.epistemic.limitationClasses).toContain('spectral_boundary_pressure');
  });

  it('projects local carrier certificates into the same Noise/Signal limit used by mesh-verifier', () => {
    const readyTrace = {
      requestId: 'ready',
      nodeIdx: 0,
      chunkIdx: 0,
      startPos: 0,
      sequenceLength: 1,
      latencyMs: 5,
      expectedLatencyMs: 25,
      requestEntropy: 4,
      boundaryLimit: 8,
      timestamp: 1,
    };
    const noisyTrace = {
      requestId: 'noisy',
      nodeIdx: 1,
      chunkIdx: 0,
      startPos: 0,
      sequenceLength: 1,
      latencyMs: 5,
      expectedLatencyMs: 25,
      requestEntropy: 32,
      boundaryLimit: 8,
      timestamp: 2,
    };
    const readyAssessment = toMeshCarrierAssessmentWire({
      stationLayerStart: 0,
      stationLayerEndExclusive: 1,
      spectral: classifySpectralNoise(readyTrace, [], TOWER_CEILINGS.hexon),
    });
    const noisyAssessment = toMeshCarrierAssessmentWire({
      stationLayerStart: 1,
      stationLayerEndExclusive: 2,
      spectral: classifySpectralNoise(noisyTrace, [], TOWER_CEILINGS.hexon),
    });

    const signal = computeMeshCarrierNoiseSignalFromAssessments(
      [readyAssessment],
      1,
    );
    expect(signal.signal).toBe(1);
    expect(signal.noise).toBe(0);
    expect(signal.noiseSignalLimit).toBe(1);
    expect(signal.interpretation).toBe('signal-supported');

    const mixed = computeMeshCarrierNoiseSignalFromAssessments(
      [readyAssessment, noisyAssessment],
      2,
    );
    expect(mixed.signal).toBe(1);
    expect(mixed.noise).toBe(1);
    expect(mixed.noiseSignalLimit).toBe(0);
    expect(mixed.interpretation).toBe('signal-supported');
    expect(mixed.readinessMargin).toBeLessThan(0);
    expect(mixed.theoremLineage).toContain(
      'Gnosis.HornLayeredReadiness.matched_horn_readiness_eq_carrier_readiness',
    );

    const noise = computeMeshCarrierNoiseSignalFromAssessments(
      [noisyAssessment],
      2,
    );
    expect(noise.signal).toBe(0.5);
    expect(noise.noise).toBe(1);
    expect(noise.noiseSignalLimit).toBe(-0.5);
    expect(noise.interpretation).toBe('noise-burdened');
  });

  it('merges deblur fold onto existing JSON', () => {
    const trace = {
      requestId: 'r',
      nodeIdx: 0,
      chunkIdx: 0,
      startPos: 0,
      sequenceLength: 1,
      latencyMs: 10,
      expectedLatencyMs: 25,
      requestEntropy: 1,
      boundaryLimit: 8,
      timestamp: 1,
    };
    const assessment = classifySpectralNoise(trace, [], TOWER_CEILINGS.hexon);
    const base = encodeMeshCarrierAssessmentV1Json({
      stationLayerStart: 0,
      stationLayerEndExclusive: 1,
      spectral: assessment,
    });
    const merged = mergeDeblurFoldIntoMeshCarrierJson(base, {
      foldRounds: 2,
      foldSurvivors: 1,
      foldRejected: 1,
      foldTotalWeight: 1,
      candidateLabels: ['a'],
      selectedSigmas: [0.9],
      watermark: {
        id: 'wm-1',
        mode: 'luma_spread',
        strength: 0.02,
        seedDigest: 'abc12345',
        payloadBits: 64,
      },
    });
    const parsed = JSON.parse(merged) as {
      deblurFold: { foldRounds: number; watermark?: { id: string } };
    };
    expect(parsed.deblurFold.foldRounds).toBe(2);
    expect(parsed.deblurFold.watermark?.id).toBe('wm-1');
  });

  it('attachDeblurEnsembleToMeshCarrierAssessmentJson merges forkRaceFoldDeblur output', async () => {
    const w = 24;
    const h = 24;
    const data = new Float32Array(w * h);
    for (let i = 0; i < data.length; i++) {
      data[i] = 0.4 + (i % 17) * 0.001;
    }
    const ensemble = await forkRaceFoldDeblur({
      input: { data, width: w, height: h, channels: 1 },
      configs: [{ label: 'wiener-tiny', options: { sigma: 1.2, method: 'wiener' } }],
    });
    const trace = {
      requestId: 'deblur-merge',
      nodeIdx: 0,
      chunkIdx: 0,
      startPos: 0,
      sequenceLength: 1,
      latencyMs: 5,
      expectedLatencyMs: 25,
      requestEntropy: 1,
      boundaryLimit: 8,
      timestamp: 1,
    };
    const assessment = classifySpectralNoise(trace, [], TOWER_CEILINGS.hexon);
    const base = encodeMeshCarrierAssessmentV1Json({
      stationLayerStart: 0,
      stationLayerEndExclusive: 1,
      spectral: assessment,
    });
    const merged = attachDeblurEnsembleToMeshCarrierAssessmentJson(base, ensemble);
    const parsed = JSON.parse(merged) as {
      deblurFold: { candidateLabels: string[]; foldSurvivors: number };
    };
    expect(parsed.deblurFold.candidateLabels).toContain('wiener-tiny');
    expect(parsed.deblurFold.foldSurvivors).toBeGreaterThanOrEqual(1);
  });

  it('meshCarrierRequestHeadersWithDeblurEnsemble encodes ensemble for worker header', async () => {
    const w = 16;
    const h = 16;
    const data = new Float32Array(w * h);
    for (let i = 0; i < data.length; i++) data[i] = 0.5;
    const ensemble = await forkRaceFoldDeblur({
      input: { data, width: w, height: h, channels: 1 },
      configs: [{ label: 'h1', options: { sigma: 1, method: 'wiener' } }],
    });
    const headers = meshCarrierRequestHeadersWithDeblurEnsemble(ensemble);
    const b64 = headers[MESH_HTTP_HEADER_CARRIER_DEBLUR_FOLD];
    expect(b64).toBeTruthy();
    const fold = JSON.parse(Buffer.from(b64, 'base64').toString('utf8')) as {
      candidateLabels: string[];
      watermark?: { id: string };
    };
    expect(fold.candidateLabels).toContain('h1');
    expect(fold.watermark).toBeUndefined();
  });

  it('includes optional deblur fold when supplied', () => {
    const trace = {
      requestId: 'r',
      nodeIdx: 0,
      chunkIdx: 0,
      startPos: 0,
      sequenceLength: 1,
      latencyMs: 10,
      expectedLatencyMs: 25,
      requestEntropy: 1,
      boundaryLimit: 8,
      timestamp: 1,
    };
    const assessment = classifySpectralNoise(trace, [], TOWER_CEILINGS.hexon);
    const fold = {
      foldRounds: 1,
      foldSurvivors: 2,
      foldRejected: 0,
      foldTotalWeight: 1,
      candidateLabels: ['a', 'b'] as const,
      selectedSigmas: [0.5, 0.6] as const,
    };
    const wire = toMeshCarrierAssessmentWire({
      stationLayerStart: 0,
      stationLayerEndExclusive: 1,
      spectral: assessment,
      deblurFold: fold,
    });
    expect(wire.deblurFold?.candidateLabels).toEqual(['a', 'b']);
  });
});
